### enccc.py

# N =  
# e =  
# c =  

from Crypto.Util.number import *

p = getPrime(512)
q = getPrime(512)
N = p*q
phi = (p-1)*(q-1)

while True:
	d = getPrime(256)
	if GCD(d, phi) == 1:
		break

e = inverse(d, phi)

with open("flaggg.txt", "rb") as f:
    m = bytes_to_long(f.read())

assert m < N 

c = pow(m, e, N)

print("N = ", N)
print("e = ", e)
print("c = ", c)